import io.harbor.textd.core.*;
import java.lang.management.*;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;

public class Diag {
  private static final String SAMPLE = "alpha beta gamma";
  private static final ClassLoadingMXBean CLASS_LOADING = ManagementFactory.getClassLoadingMXBean();
  public static void main(String[] args) throws Exception {
    long loadedBefore = CLASS_LOADING.getLoadedClassCount();
    long unloadedBefore = CLASS_LOADING.getUnloadedClassCount();
    TextDaemon daemon = new TextDaemon(Path.of("build/plugins/customer-default.jar"), 4);
    daemon.reload(1);
    List<ProcessingResult> firstResults = daemon.processBatch(List.of(SAMPLE, SAMPLE, SAMPLE, SAMPLE));
    List<String> workersStart = firstResults.stream().map(ProcessingResult::workerThread).sorted().collect(Collectors.toList());
    List<ProcessingResult> finalResults = firstResults;
    for (int current = 2; current <= 4; current++) {
      daemon.reload(current);
      finalResults = daemon.processBatch(List.of(SAMPLE, SAMPLE, SAMPLE, SAMPLE));
    }
    List<String> workersEnd = finalResults.stream().map(ProcessingResult::workerThread).sorted().collect(Collectors.toList());
    boolean sameWorkers = workersStart.equals(workersEnd);
    boolean beforeClose = daemon.isBalanced();
    String first = firstResults.get(0).output();
    String last = finalResults.get(0).output();
    daemon.close();
    for (int i = 0; i < 3; i++) { System.gc(); Thread.sleep(50); }
    boolean afterClose = daemon.isBalanced();
    System.out.println("sameWorkers=" + sameWorkers + " before=" + beforeClose + " after=" + afterClose + " first=" + first + " last=" + last);
    System.out.println("loadedBefore=" + loadedBefore + " loadedAfter=" + CLASS_LOADING.getLoadedClassCount());
    System.out.println("unloadedBefore=" + unloadedBefore + " unloadedAfter=" + CLASS_LOADING.getUnloadedClassCount());
  }
}
